Python <pre><code>from abc import ABC, abstractclassmethod


class Product(ABC):
    """Интерфейс продукта"""
    @abstractclassmethod
    def product(self):
        ...

class ConcreteProduct(Product):
    """Конкретный продукт"""
    def product(self):
        return self.__class__.__name__

class Creator(ABC):
    """Создатель"""
    @abstractclassmethod
    def factory(self) -&gt; Product: pass

class ConcreteCreator(Creator):
    """Реализация создателя"""
    def factory(self) -&gt; Product:
        return ConcreteProduct()

if __name__ == "__main__":
    creator: Creator = ConcreteCreator()

    product: Product = creator.factory()

    print(product.product())
