Python <pre><code>from abc import ABC, abstractclassmethod


class Figure(ABC):
    @abstractclassmethod
    def square(self):
        ...

    @abstractclassmethod
    def clone(self):
        ...


class Rectangle(Figure):
    def __init__(self, a: int, b: int) -&gt; None:
        self._a = a
        self._b = b

    def square(self):
        return self._a * self._b

    def clone(self) -&gt; 'Rectangle':
        return Rectangle(a=self._a, b=self._b)

if __name__ == "__main__":
    rectangle: Figure = Rectangle(1, 1)

    print(rectangle.square())

    rectangle_2: Figure = rectangle.clone()

    print(rectangle_2.square())
